use std::fs;
use std::path::Path;

/// The static portion of the type declarations for the global `Tako` object.
const TAKO_DTS_HEADER: &str = r#"/**
 * Tako global API — injected at runtime by the Tako entrypoint.
 *
 * Generated by Tako CLI. Do not edit manually.
 * To update, run `tako init` again or upgrade your Tako CLI.
 */
"#;

/// Build the full `tako.d.ts` content, including typed secrets.
fn build_dts(secret_names: &[String]) -> String {
    let mut out = String::from(TAKO_DTS_HEADER);

    if secret_names.is_empty() {
        out.push_str(
            r#"// eslint-disable-next-line @typescript-eslint/no-empty-object-type
interface TakoSecrets {}
"#,
        );
    } else {
        out.push_str("interface TakoSecrets {\n");
        for name in secret_names {
            out.push_str(&format!("  readonly {}: string;\n", name));
        }
        out.push_str("  toString(): \"[REDACTED]\";\n");
        out.push_str("  toJSON(): \"[REDACTED]\";\n");
        out.push_str("}\n");
    }

    out.push_str(
        r#"
declare const Tako: {
  secrets: TakoSecrets;
};
"#,
    );

    out
}

/// Write `tako.d.ts` to the project root.
///
/// Returns `true` if the file was written (created or updated),
/// `false` if it already existed with the same content.
pub fn write_types(project_dir: &Path) -> std::io::Result<bool> {
    let secret_names = read_secret_names(project_dir);
    write_types_with_secrets(project_dir, &secret_names)
}

/// Write `tako.d.ts` with explicit secret names.
pub fn write_types_with_secrets(
    project_dir: &Path,
    secret_names: &[String],
) -> std::io::Result<bool> {
    let path = project_dir.join("tako.d.ts");
    let content = build_dts(secret_names);
    if path.is_file() {
        let existing = fs::read_to_string(&path)?;
        if existing == content {
            return Ok(false);
        }
    }
    fs::write(&path, &content)?;
    Ok(true)
}

/// Read secret names from `.tako/secrets.json` for the "development" environment.
///
/// Falls back to all secret names across all environments if no development
/// secrets exist, so that types are useful regardless of which env is active.
fn read_secret_names(project_dir: &Path) -> Vec<String> {
    let secrets_path = project_dir.join(".tako").join("secrets.json");
    let content = match fs::read_to_string(&secrets_path) {
        Ok(c) => c,
        Err(_) => return Vec::new(),
    };

    // Parse just enough to extract secret names — avoid depending on
    // the full SecretsStore type from the config crate.
    let parsed: serde_json::Value = match serde_json::from_str(&content) {
        Ok(v) => v,
        Err(_) => return Vec::new(),
    };

    let obj = match parsed.as_object() {
        Some(o) => o,
        None => return Vec::new(),
    };

    // Prefer "development" env, fall back to union of all envs
    let secret_keys: Vec<String> = if let Some(dev) = obj.get("development") {
        extract_secret_names(dev)
    } else {
        let mut all: Vec<String> = obj
            .values()
            .flat_map(|env| extract_secret_names(env))
            .collect();
        all.sort();
        all.dedup();
        all
    };

    secret_keys
}

fn extract_secret_names(env_value: &serde_json::Value) -> Vec<String> {
    let secrets = env_value.get("secrets").and_then(|s| s.as_object());
    match secrets {
        Some(map) => {
            let mut names: Vec<String> = map.keys().cloned().collect();
            names.sort();
            names
        }
        None => Vec::new(),
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    #[test]
    fn write_types_creates_file() {
        let dir = TempDir::new().unwrap();
        let written = write_types(dir.path()).unwrap();
        assert!(written);

        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("declare const Tako"));
        assert!(content.contains("TakoSecrets"));
    }

    #[test]
    fn write_types_is_idempotent() {
        let dir = TempDir::new().unwrap();
        assert!(write_types(dir.path()).unwrap());
        // Second call should detect identical content
        assert!(!write_types(dir.path()).unwrap());
    }

    #[test]
    fn write_types_updates_stale_file() {
        let dir = TempDir::new().unwrap();
        fs::write(dir.path().join("tako.d.ts"), "// old types").unwrap();
        let written = write_types(dir.path()).unwrap();
        assert!(written);

        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("declare const Tako"));
    }

    #[test]
    fn write_types_with_secrets_generates_typed_interface() {
        let dir = TempDir::new().unwrap();
        let names = vec!["API_KEY".to_string(), "DATABASE_URL".to_string()];
        let written = write_types_with_secrets(dir.path(), &names).unwrap();
        assert!(written);

        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("readonly API_KEY: string;"));
        assert!(content.contains("readonly DATABASE_URL: string;"));
        assert!(content.contains("toString(): \"[REDACTED]\""));
        assert!(content.contains("toJSON(): \"[REDACTED]\""));
    }

    #[test]
    fn write_types_reads_secrets_from_development_env() {
        let dir = TempDir::new().unwrap();
        let secrets_dir = dir.path().join(".tako");
        fs::create_dir_all(&secrets_dir).unwrap();
        fs::write(
            secrets_dir.join("secrets.json"),
            r#"{
                "development": {
                    "salt": "dGVzdA==",
                    "secrets": {
                        "DEV_KEY": "encrypted",
                        "DEV_DB": "encrypted"
                    }
                },
                "production": {
                    "salt": "cHJvZA==",
                    "secrets": {
                        "PROD_KEY": "encrypted"
                    }
                }
            }"#,
        )
        .unwrap();

        let written = write_types(dir.path()).unwrap();
        assert!(written);

        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        // Should use development env secrets
        assert!(content.contains("readonly DEV_DB: string;"));
        assert!(content.contains("readonly DEV_KEY: string;"));
        // Should NOT include production-only secrets
        assert!(!content.contains("PROD_KEY"));
    }

    #[test]
    fn write_types_falls_back_to_all_envs_when_no_development() {
        let dir = TempDir::new().unwrap();
        let secrets_dir = dir.path().join(".tako");
        fs::create_dir_all(&secrets_dir).unwrap();
        fs::write(
            secrets_dir.join("secrets.json"),
            r#"{
                "production": {
                    "salt": "cHJvZA==",
                    "secrets": {
                        "PROD_KEY": "encrypted"
                    }
                }
            }"#,
        )
        .unwrap();

        write_types(dir.path()).unwrap();

        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("readonly PROD_KEY: string;"));
    }
}
